import{_ as n,j as i,o as t,v as h}from"./chunks/framework.dn0DPyqd.js";const a=JSON.parse('{"title":"Fallacies of distributed computing - Những sai lầm khi sử dụng distributed computing","description":"Từ những phiên bản đầu tiên khi Kafka được Open Source đến phiên bản 2.3.1, mặc định Kafka producer khi gửi các Record có key là null sẽ thực hiện Round Robin Partition","frontmatter":{"footer":true,"title":"Fallacies of distributed computing - Những sai lầm khi sử dụng distributed computing","description":"Từ những phiên bản đầu tiên khi Kafka được Open Source đến phiên bản 2.3.1, mặc định Kafka producer khi gửi các Record có key là null sẽ thực hiện Round Robin Partition","authors":["lethanh"],"date":"2024-10-09T00:00:00.000Z","outline":"deep","image":"/assets/KafkaProducer12.qYn0oVGH.png","draft":true},"headers":[{"level":2,"title":"Những sai lầm.","slug":"nhung-sai-lam","link":"#nhung-sai-lam","children":[{"level":3,"title":"The network is reliable","slug":"the-network-is-reliable","link":"#the-network-is-reliable","children":[{"level":4,"title":"Giải pháp The network is reliable.","slug":"giai-phap-the-network-is-reliable","link":"#giai-phap-the-network-is-reliable","children":[]}]},{"level":3,"title":"Latency is zero","slug":"latency-is-zero","link":"#latency-is-zero","children":[{"level":4,"title":"Giải pháp Latency is zero.","slug":"giai-phap-latency-is-zero","link":"#giai-phap-latency-is-zero","children":[]}]},{"level":3,"title":"Bandwidth is infinite","slug":"bandwidth-is-infinite","link":"#bandwidth-is-infinite","children":[{"level":4,"title":"Các thiệt hại khi đạt giới hạn Bandwidth hoặc lạm dụng Bandwidth.","slug":"cac-thiet-hai-khi-đat-gioi-han-bandwidth-hoac-lam-dung-bandwidth","link":"#cac-thiet-hai-khi-đat-gioi-han-bandwidth-hoac-lam-dung-bandwidth","children":[]},{"level":4,"title":"Giải pháp Bandwidth is infinite.","slug":"giai-phap-bandwidth-is-infinite","link":"#giai-phap-bandwidth-is-infinite","children":[]}]}]},{"level":2,"title":"Network is secure","slug":"network-is-secure","link":"#network-is-secure","children":[{"level":3,"title":"Hệ thống của chúng ta Nên làm gì để đảm bảo Network is secure.","slug":"he-thong-cua-chung-ta-nen-lam-gi-đe-đam-bao-network-is-secure","link":"#he-thong-cua-chung-ta-nen-lam-gi-đe-đam-bao-network-is-secure","children":[]},{"level":3,"title":"Topology doesn\'t change","slug":"topology-doesn-t-change","link":"#topology-doesn-t-change","children":[]}]}],"relativePath":"blog/2024-10-09-Fallacies-of-distributed-computing-nhung-sai-lam-cua-khi-su-dung-distributed-computing.md","filePath":"blog/2024-10-09-Fallacies-of-distributed-computing-nhung-sai-lam-cua-khi-su-dung-distributed-computing.md","lastUpdated":1730999335000}'),l={name:"blog/2024-10-09-Fallacies-of-distributed-computing-nhung-sai-lam-cua-khi-su-dung-distributed-computing.md"},c=[h('<p>Fallacies of distributed computing là một tập hợp các khẳng định được tập hợp bởi <a href="https://en.wikipedia.org/wiki/L._Peter_Deutsch" target="_blank" rel="noreferrer">L. Peter Deutsch</a> và một số người tại <a href="https://en.wikipedia.org/wiki/Sun_Microsystems" target="_blank" rel="noreferrer">Sun Microsystems</a> mô tả về những giả định sai lầm của các lập tình viên đanng làm việc với ứng dụng phân tán.</p><p>Tuy nhiên trong bài viết này mình sẽ dựa vào khái niệm Fallacies of distributed computing để mapping nó về phát triển ứng dụng, phần mềm trong hệ thống microservices.</p><p>Điều này sẽ giúp các bạn có cái nhìn tổng quan về những sai lầm mà các lập trình viên hay gặp phải khi phát triển và triển khai ứng dụng của mình lên cho người dùng sử dụng.</p><h2 id="nhung-sai-lam" tabindex="-1">Những sai lầm. <a class="header-anchor" href="#nhung-sai-lam" aria-label="Permalink to &quot;Những sai lầm.&quot;">​</a></h2><h3 id="the-network-is-reliable" tabindex="-1">The network is reliable <a class="header-anchor" href="#the-network-is-reliable" aria-label="Permalink to &quot;The network is reliable&quot;">​</a></h3><p><strong>The network is reliable</strong>: Dịch tiếng việt là <code>Mạng lưới đáng tin cậy</code>. Đây là 1 sai lầm nghiêm trọng nhưng cũng hay xảy ra bởi các lập trình viên mới.</p><p>Thông thường, các hệ thống sẽ phụ thuộc vào 1 hoặc N các hệ thống khác để hoạt động. Nghĩa là trong quá trình hoàn thành nghiệm vụ của mình, hệ thống sẽ cần gọi đến 1 hoặc N hệ thống khác để hoàn thành nghiêm vụ của mình.</p><p>Câu hỏi đặt ra là: Điều gì sẽ xảy ra khi việc thực hiện gọi đến hệ thống khác không thành công? (Ví dụ timeout hoặc không thể kết nối)</p><p>Rất nhiều lập trình viên tin rằng các kết nối các hệ thống khác sẽ hoạt động tốt và luôn không có vấn đề gì xảy ra. Tuy nhiên kết nối mạng rất sẽ bị lỗi bởi nhiều nguyên nhân như:</p><ul><li>Vấn đề phần mềm.</li><li>Vấn đề phần cứng.(Giới hạn phần cứng, hỏng hóc phần cứng)</li><li>Vấn đề bảo mật(Thiếp lập ssl/tls thất bại...etc..)</li><li>Môi trường mạng không ổn định.</li><li>Một diễn biến xấu: Ví dụ hệ thống khác bị tấn công từ chối dịch vụ (DDoS) hoặc bị tấn công bảo mật.</li></ul><p>Một hệ thống tốt cần có một cơ chế linh loạt bao gồm đầy đủ các tính năng dự phòng khi mất kết nối đến các hệ thống khác.</p><div data-svg="data-diagram-plantuml" class="diagram-m"><img src="https://www.plantuml.com/plantuml/svg/TL91JWCn3Bpd5POu8t7U0q9qMu44257w0BCrswZPfDZUhlfxd3IKLeYSaXbxF9daJXHPno4usVguGyO1Fh3Rzfp6k9wba1YkvlFvVJixgv0DhjFaOm-V68JE66HEKssxAUkSx3JnKW-102UID91pwjMExnk25z8fyHQym1i5Zn-6Bp04x0xEbLPO2J6WmAgUMzfJIBiZs3gtWkjRM1v4QMXWIN5jIbyZYReZcEawfe5tnYY3LsXHqM7GauC5-Z0oER3rWvq9prACrAbF4PwIQUUoN_rL0tCBWU6PHB0dHvRGIMOvTftXVwI9zyGDB19FoEkZfQ9RY0lVzLwoIr7-zTXQWhdnekx2v1lfoF4uoHITYqa9sFSRXVHPQqlReuXb21sEafyyrcbZvF9CFdWzDANo-cIbIx6tt2sZIZpOjUngP3-cX2iLVoKUl4WEqvSv5N-CcXbLYfhLIk9xcvJDGlRgt9rjxUj-0m00" alt="uml diagram"></div><h4 id="giai-phap-the-network-is-reliable" tabindex="-1">Giải pháp <code>The network is reliable</code>. <a class="header-anchor" href="#giai-phap-the-network-is-reliable" aria-label="Permalink to &quot;Giải pháp `The network is reliable`.&quot;">​</a></h4><details class="details custom-block"><summary>Chi tiết</summary><p>Sẽ có rất nhiều cách để đảm bảo hệ thống của chúng ta là <code>network is reliable</code> khi chúng ta là phụ thuộc của các hệ thống khác, dưới đây là một số ví dụ.(Có thể kết hợp nhiều cách để đảm bảo hệ thống của chúng ta là <code>network is reliable</code>).</p><ul><li>Cung cấp tính năng Retry Mechanism để thử lại kết nối khi kết nối bị lỗi.</li><li>Sử dụng Queue, Thông thường các hệ thống queue sẽ có tính năng retry mechanism chuyển message đến người nhận lỗi. <ul><li>Nếu 1 tin nhắn không thể gửi(Max retry..etc..) thì nó có thể được chuyển đến một hệ thống khác để xử lý hoặc <a href="https://en.wikipedia.org/wiki/Dead_letter_queue" target="_blank" rel="noreferrer">Dead letter queue</a></li></ul></li><li>Một điều quan trọng đó là ngay khi thiết kế hệ thống hoặc lập trình viên code thì phải có tư tưởng là sẽ có lỗi mạng.</li><li>...</li></ul></details><h3 id="latency-is-zero" tabindex="-1">Latency is zero <a class="header-anchor" href="#latency-is-zero" aria-label="Permalink to &quot;Latency is zero&quot;">​</a></h3><p><strong>Latency is zero</strong> : Dịch tiếng việt là độ trễ là 0.</p><p>Độ trễ có thể hiểu đơn giản là một sự kích thích và phản ứng tương ứng với kích thích đó.</p><ul><li>Ví dụ: Khi bạn buồn ngủ, bạn uống cafe và sau 5 phút bạn không còn buồn ngủ. Cafe là kích thích, và việc bạn không còn buồn ngủ là phản ứng tương ứng với kích thích đó và 5 phút là độ trễ.</li></ul><p>Trong thuật ngữ mạng đó là thời gian để di chuyển data từ vị trí A đến vị trí khác thông qua mạng. Trong thuật ngữ phần mềm đó là thời gian để xử lý một yêu cầu từ người dùng và trả về kết quả cho người dùng. ....</p><p>Tất cả hành động đều có độ trễ, không có hành động nào có độ trễ là 0. Dù bản thân con người cũng có độ trễ, nhưng nó đủ nhanh để không cảm nhận được độ trễ nhưng nó vẫn tồn tại.</p><p>Việc hạn chế có các độ chễ không cần thiết khi phát triển ứng dụng là một điều cần thiết. Có nhiều các độ chễ nhỏ có thể tính bằng mili giây nhưng nếu có quá nhiều độ chễ nhỏ thì nó có thể tính bằng giây hoặc phút.</p><p>Khi phát triển ứng dụng, chúng ta cần phải nhớ rằng mọi hành động đều có độ trễ và nó có thể tính bằng phút. <img src="/assets/network-latency.WLz64lxW.png" alt="img"></p><p>Một ví dụ điển trình của điều này chính là ORM. Khi sử dụng ORM, chúng ta có thể cấu hình Lazy load và Eager Loading.</p><ul><li>Lazy load: Khi cấu hình Lazy load, dữ liệu sẽ chỉ được load khi cần thiết, điều này có thể tạo ra độ trễ khi bắt đầu sử dụng dữ liệu. <ul><li>Tuy nhiên nó cũng có 2 mặt, nếu dữ liệu đó không cần thiết thì nó sẽ không load dữ liệu đó, giúp giảm tải cho hệ thống.</li><li>Ví dụ: Học sinh Tuấn vào màn hình danh sách lịch học trong tháng: <ul><li>Nếu cấu hình Lazy load: Dữ liệu sẽ được load khi Tuấn click vào từng ngày, mỗi lần click sẽ có độ trễ khoảng 0.5s, tuy nhiên tại màn hình danh sách chỉ tốn 1s.</li></ul></li></ul></li><li>Eager Loading: Khi cấu hình Eager Loading, tất cả dữ liệu sẽ được load ngay khi truy vấn, điều này có thể tạo ra độ trễ khi truy vấn số lượng lớn dữ liệu. <ul><li>Giống với Lazy load, Eager Loading cũng có 2 mặt, nếu dữ liệu đó không được sử dụng thì nó sẽ tạo ra độ trễ không cần thiết.</li><li>Ví dụ: Học sinh Tuấn vào màn hình danh sách lịch học trong tháng: <ul><li>Nếu cấu hình Eager Loading: Dữ liệu sẽ được load ngay khi vào màn hình và tần tốn 3s để load dữ liệu.</li></ul></li></ul></li></ul><h4 id="giai-phap-latency-is-zero" tabindex="-1">Giải pháp <code>Latency is zero</code>. <a class="header-anchor" href="#giai-phap-latency-is-zero" aria-label="Permalink to &quot;Giải pháp `Latency is zero`.&quot;">​</a></h4><details class="details custom-block"><summary>Chi tiết</summary><ul><li>Sử dụng Cache để không cần tính toán lại dữ liệu đã được tính toán trước đó. <ul><li>Có thể sử dụng Cache ở nhiều cấp độ, từ cấp độ ứng dụng, cấp độ hệ thống...</li><li>Có thể cache ở nhiều nơi như Redis, Memcached, CDN, Local Storage...etc...</li></ul><div data-svg="data-diagram-plantuml" class="diagram-m"><img src="https://www.plantuml.com/plantuml/svg/RLBDQiCm3BxlAGGx5tREOPGb7JkiK1PosKrrrCJKiJjBQScUVdQSDYMTmG7f-v4iPSs2NlhEF44uVDJsX1uxsACwDjxrjiwTSHwUDvlDMv4lMDnYxIxQDd10mxH0qNjtcUGluraIb3XVoc08y4BikkGmVaHBI7-Ya5K3Q8Plycw6HobKJ1wGeRhB5NGcuqu9A6P51QjNA0SMwZ8eoTRmHJyziOne0Y8bHzLI1dbBwfY2P6uaHV2XaoH5GL5bmKfwRrEgXW85Hmg5eKoyhMPUL8gqFN8ezawYsbbs1UuxdYhSE0yDb-7nz1zUFOh3w-V1M2S4NZUjW3jCkcGXFeo_qSGW3ZpLlI8mQIFPo5Z53TmDAMQsskfE_mPBwgApGcFuXkxQWNLC3Q2CY-iBzqp-oeXxYGtTsbk7JFWz_m00" alt="uml diagram"></div></li><li>Hạn chế sử dụng các remote call(Call database, rest, rpc...etc..) thừa thãi.</li><li>Về mặt vật lý, nếu dữ liệu hoặc máy chủ ở gần khách hàng thì độ trễ sẽ giảm.</li></ul><div data-svg="data-diagram-plantuml" class="diagram-m"><img src="https://www.plantuml.com/plantuml/svg/RLF1Rjim3BthAuZs761d7uQkTeOMw8fkRYwxiJ8J2t74LgGRf5y_IauN7QgBHJwIZu-KRqGnwNoOdEn3VCM41tX1lzybdkFGyiG9hjVhzMtNLX4oui3747UmnKceGZ0bFfxJlfLJWruvzNgQ2F18mWToJeEQ-O1AqPyW2FobnCwLKDW89K21pTdkw9qcVbsSdNCRM7s7_YHAXmPwYWFyeRUPHDtYpF03ut2B4qPFgO4kYARmCYiLmDLeZcwxnrmflHFqYXeyj1ojDtM6v81DOnmwfmWj-f66_tX5MP06sf7yVZ4SJhhSu2we0pkBzLN53XKTsLpFCR-2I4cvC9GEJSvFKZyk2IMWkAiMUfiQVOLVI1UsEDG2VipAlSSfKvGltCTjGXlTx2s9gj3Vt3Vmb0AdeE63u3dXTXjyNKnEqO-98y_obDYJYBsS1kum3bRvaUEgpSd60yyeUt4kikqdXTsemDkpx4M09difkq02oa1HSZCPkAfUq8UzeAkck5Tbox1is5ZFJjlbvytcTF5dtIknHYukq_S9LZhW8YJF3dB3pjtOrNwbVm00" alt="uml diagram"></div></details><h3 id="bandwidth-is-infinite" tabindex="-1">Bandwidth is infinite <a class="header-anchor" href="#bandwidth-is-infinite" aria-label="Permalink to &quot;Bandwidth is infinite&quot;">​</a></h3><p><strong>Bandwidth is infinite</strong>: Dịch tiếng việt là Băng thông là vô hạn.</p><p>Bằng thông hiểu đơn giản là tốc chạy của chúng ta mỗi giây. Trong mạng cũng vậy, băng thông là tốc độ truyền dữ liệu mỗi giây. <a href="https://www.nngroup.com/articles/law-of-bandwidth/" target="_blank" rel="noreferrer">Mặc dù băng thông đã tăng rất nhiều trong vài thập kỷ qua nhưng nó không phải là vô hạn.</a></p><p>Người dùng có thể không đủ may mắn để trải nghiệm băng thông mạng cao, bởi do nhiều vấn đề. Ví dụ như: Họ dùng mạng di động. <a href="https://en.wikipedia.org/wiki/List_of_sovereign_states_by_Internet_connection_speeds" target="_blank" rel="noreferrer">Họ dùng mạng ở Việt Nam chứ không phải ở Singapore.</a></p><p>Một điều nữa là do băng thông tăng lên, nên các yêu cầu về dữ liệu lớn cũng tăng lên. Ví dụ như video 4k, 8k, 16k...etc...</p><p>Có lẽ bạn chưa biết, các VPS hoặc cloud ở Việt Nam thường có Bandwidth tối đa là 100 Mb/s. Nếu ứng dụng chúng ta sử dụng Bandwidth vượt quá giới hạn ứng dụng của chúng ta có thể bị tắc nghẽn.</p><p>Và tất nhiên chính thiết bị phần cứng của chúng ta cũng có giới hạn. Nếu tốc độ vượt quá giới hạn phần cứng thì hệ thống của chúng ta sẽ bị tắc nghẽn.</p><ul><li>Ví dụ 1: Ứng dụng của chúng ta cung cấp chức năng xem phim, nếu có quá nhiều người xem phim cùng lúc thì hệ thống của chúng ta sẽ bị tắc nghẽn.</li></ul><div data-svg="data-diagram-plantuml" class="diagram-m"><img src="https://www.plantuml.com/plantuml/svg/VLDDRzim3BthLn3OETZEEGpzI8eM60eiQNu0Op6s45bqAJf6-kj7EKxhODXqiQJ7n_T8odTPKRHleyl7a3eKR66FrR4MxfD_vCW2tzRhzSFgSHQH6_GyX5J30MEc6O8YF4oq7-EQWvMoRFKS2N2Wp2qvfq7j-8393y5h0o73Ipg459JW2MF4wkpSI8HT9W7Ci9lEApfHvEvokN9k1ukVi3rdfNO9MqeUDlJUKrPtkIpmA-d0Sbp2cs3ARL1OeQB3g3CFlq81DeHLGzw1hOas5tXhXBLu7nEKe2-LdUb77Yn5xZXPWyYwD1EuFs68k8_qLtAI4yaIdbW653_BFG8t5KmLJWh_SBcY60hn9kx6w8QqbtHHiepE9RRMIwWR1JvCiIFj9MVh9bJOvpBw_MSviVGBDPZ0SenSV5gfEDKs0OCcuDdAij9eJhf2fWdUV82drfBduWUAdV-OsggWKXtCc38O3MlwidQrSvcelTaK6VttlYiVo1sHlwh_vYrq4bY2XW-SETwGxoiJjmVRYsro-A0hwRvNNkGAOsb8I0V1hD9Nrb6QcR-phVrYVm00" alt="uml diagram"></div><h4 id="cac-thiet-hai-khi-đat-gioi-han-bandwidth-hoac-lam-dung-bandwidth" tabindex="-1">Các thiệt hại khi đạt giới hạn Bandwidth hoặc lạm dụng Bandwidth. <a class="header-anchor" href="#cac-thiet-hai-khi-đat-gioi-han-bandwidth-hoac-lam-dung-bandwidth" aria-label="Permalink to &quot;Các thiệt hại khi đạt giới hạn Bandwidth hoặc lạm dụng Bandwidth.&quot;">​</a></h4><ul><li>Có thể gây tắc nghẽn hệ thống, request người dùng sẽ không thể đáp ứng hoặc đáp ứng chậm.</li><li>Đa số các bên cho thuê VPS và Cloud đều sẽ tính phí mạng, nếu lạm dụng mạng có thể dẫn đến chi phí cao.</li><li>Lạm dụng băng thông có thể làm tăng nguy cơ bị tấn công từ chối dịch vụ (DDoS), làm giảm khả năng bảo mật của hệ thống.</li><li>Khi băng thông bị giới hạn, khả năng mở rộng của hệ thống cũng bị ảnh hưởng, làm giảm khả năng phục vụ số lượng lớn người dùng cùng lúc.</li></ul><h4 id="giai-phap-bandwidth-is-infinite" tabindex="-1">Giải pháp <code>Bandwidth is infinite</code>. <a class="header-anchor" href="#giai-phap-bandwidth-is-infinite" aria-label="Permalink to &quot;Giải pháp `Bandwidth is infinite`.&quot;">​</a></h4><details class="details custom-block"><summary>Chi tiết</summary><ul><li>Giới hạn tốc độ download và upload của người dùng.</li><li>QoS: Cấu hình phòng ngừa để ưu tiên các tính năng trọng hơn khi sự cố xảy ra. Để đảm bảo rằng các dịch vụ quan trọng nhất của bạn vẫn hoạt động tốt nhất có thể.</li><li>Giảm kích thước của các tài nguyên như hình ảnh, script và stylesheet để giảm lượng dữ liệu truyền tải.</li><li>Tự động mở rộng hạ tầng dựa trên nhu cầu lưu lượng để xử lý các tải khác nhau một cách hiệu quả.</li></ul></details><h2 id="network-is-secure" tabindex="-1">Network is secure <a class="header-anchor" href="#network-is-secure" aria-label="Permalink to &quot;Network is secure&quot;">​</a></h2><p>Ngày nay(2024) các lập trình viên ở Việt Nam chú trọng nhiều vào việc phát triển chức năng, tối ưu hóa hệ thống, tối ưu hóa tốc độ, tối ưu hóa bộ nhớ, tối ưu hóa cơ sở dữ liệu... nhưng ít chú trọng vào việc bảo mật hệ thống.</p><p>Dù lập trình viên có chú ý bảo mật hệ thống trong code của mình rất tốt nhưng khi dữ liệu đi qua mạng thì không được mã hóa thì hệ thống của chúng ta vẫn không an toàn.</p><p>Hiện tại khi dữ liệu đi qua mạng thì có rất nhiều cách để hacker hoặc các hệ thống trung gian đứng giữa đánh cắp dữ liệu hoặc thay đổi dữ liệu gây ra vấn đề giả mạo yêu cầu hoặc truy cập trái phép.</p><p>Một trong những khái niệm phổ biến về kiểu tấn công này là man-in-the-middle attack.</p><p>Vì vậy hệ thống cần có các cơ chế bảo mật ở tầng mạng để đảm bảo dữ liệu của chúng ta không bị đánh cắp hoặc thay đổi.</p><p>Vấn đề không phải là dữ liệu của bạn có bị đánh cắp hay không; mà là khi nào dữ liệu sẽ bị đánh cắp.</p><details class="details custom-block"><summary>Chi tiết</summary><ul><li>Dù hệ thống có an toàn đến đâu, bạn có vò đầu bứt tai để bảo mật hệ thống của mình thì vẫn luôn có nguy cơ bị tấn công và bị đánh cắp dữ liệu hoặc thay đổi dữ liệu.</li><li>Vì vậy hệ thống cần có các cơ chế bảo mật ở tầng mạng để đảm bảo dữ liệu của chúng ta không bị đánh cắp hoặc thay đổi.</li></ul></details><h3 id="he-thong-cua-chung-ta-nen-lam-gi-đe-đam-bao-network-is-secure" tabindex="-1">Hệ thống của chúng ta Nên làm gì để đảm bảo <code>Network is secure</code>. <a class="header-anchor" href="#he-thong-cua-chung-ta-nen-lam-gi-đe-đam-bao-network-is-secure" aria-label="Permalink to &quot;Hệ thống của chúng ta Nên làm gì để đảm bảo `Network is secure`.&quot;">​</a></h3><details class="details custom-block"><summary>Chi tiết</summary><ul><li>Sử dụng HTTPS để mã hóa dữ liệu truyền tải giữa người dùng và hệ thống.</li><li>Sử dụng VPN để mã hóa dữ liệu truyền tải giữa các hệ thống.</li><li>Sử dụng SSH để truy cập an toàn vào hệ thống.</li><li>Sử dụng Rate Limiting để giới hạn tốc độ truy cập của người dùng.</li><li>Sử dụng Encryption để mã hóa dữ liệu truyền tải giữa các hệ thống hoặc giữa người dùng và hệ thống.</li><li>Sử dụng Multi-Factor Authentication để bảo vệ tài khoản người dùng.</li><li>Người thiết kế hệ thống và người phát triển phần mềm cần phải có tư duy về việc bảo mật dữ liệu khi gửi qua mạng.</li><li>...etc...</li></ul><div data-svg="data-diagram-plantuml" class="diagram-m"><img src="https://www.plantuml.com/plantuml/svg/VLDDRy8m3BtdLrZRPJjKsfd310Ecxi0qhNHtqng8Q1Dakwluzqk_Hc4JEJbvp_RpHwQYo5gLXP63TKTaB663sM77ldBvt1UUuNwvNBuivYE6x37tjNKxs68XD4AGsTUzsrDxnc2cdXCz5GHOa_YIZ56huVfEMdi-W1L8AAiu02qPKY4654ZxUnoqTI-nCIb4puFh93Yw79OkuzDHAOS5AfeXRk0b9r4g9x1cT59QlQPs-4N4Jyh8VjEDe6b3qehTYFD9SlHEcX8AXHMwoBf8znIjR9w7McUgeGW3uSGNwTwS4cTqr2xDBs5G7Xof3AXwM52RxKmyguydLthX8NLCcEEce4T3OLvzZuTMY5ZlsYZ_jElLSutyfx6NEM-s8Op56EULWErkh-2tlMSNH1cLTfQagOkSDCDlWBlHJaYhzsxI0X74w_L7qjjV7--zbIHnR_KYXgeYM5M5skYrMw5P5ORXr6ROCfgjQTIPQR32H_W1" alt="uml diagram"></div></details><h3 id="topology-doesn-t-change" tabindex="-1">Topology doesn&#39;t change <a class="header-anchor" href="#topology-doesn-t-change" aria-label="Permalink to &quot;Topology doesn&#39;t change&quot;">​</a></h3><ul><li></li></ul><h1 id="ref" tabindex="-1">REF <a class="header-anchor" href="#ref" aria-label="Permalink to &quot;REF&quot;">​</a></h1><ul><li><a href="https://dereklawless.ie/fallacies-of-distributed-computing-1-the-network-is-reliable/" target="_blank" rel="noreferrer">https://dereklawless.ie/fallacies-of-distributed-computing-1-the-network-is-reliable/</a></li></ul>',53)];const e=n(l,[["render",function(n,h,a,l,e,g){return t(),i("div",null,c)}]]);export{a as __pageData,e as default};
